import{_ as o,C as s,c,o as n,aj as a,G as d}from"./chunks/framework.guNMSiFm.js";const p=JSON.parse('{"title":"Data Model","description":"","frontmatter":{},"headers":[],"relativePath":"blockchain/data-model.md","filePath":"blockchain/data-model.md","lastUpdated":1777621302000}'),i={name:"blockchain/data-model.md"};function r(l,e,A,m,h,u){const t=s("MermaidRenderWrap");return n(),c("div",null,[e[0]||(e[0]=a('<h1 id="data-model" tabindex="-1">Data Model <a class="header-anchor" href="#data-model" aria-label="Permalink to &quot;Data Model&quot;">​</a></h1><p>Iroha stores ledger state in the <code>World</code>. The current model keeps the same high-level entities as Iroha 2 while changing several identifiers for Iroha 3 and Nexus flows:</p><ul><li>domains are dataspace-qualified, for example <code>payments.universal</code></li><li>accounts are canonical and domainless; the account ID is derived from the account controller</li><li>asset definitions can keep a domain/name projection, but their canonical textual address is an opaque Base58 identifier</li><li>assets are balances held by accounts for a specific asset definition</li><li>NFTs are uniquely owned records with domain-qualified IDs and metadata content</li><li>RWAs are generated-ID lots that represent off-chain assets with current owner, quantity, provenance, metadata, holds, freezes, and lifecycle controls</li></ul>',3)),d(t,{id:"mermaid_95d402a4ed292a1b44c18ef47d9862fd987c9f66d20fa24657fb520eb202bfb8a978704fc8c4d4f03e330d62a38ffa55f7713d4df778fe5764729ec40f0b9485",text:"classDiagram%0A%0Aclass%20World%0Aclass%20Domain%20%7B%0A%20%20id%3A%20DomainId%0A%20%20logo%3A%20Option%3CSorafsUri%3E%0A%20%20metadata%3A%20Metadata%0A%20%20owned_by%3A%20AccountId%0A%7D%0Aclass%20Account%20%7B%0A%20%20id%3A%20AccountId%0A%20%20metadata%3A%20Metadata%0A%20%20label%3A%20Option%3CAccountAlias%3E%0A%20%20uaid%3A%20Option%3CUniversalAccountId%3E%0A%20%20opaque_ids%3A%20Vec%3COpaqueAccountId%3E%0A%7D%0Aclass%20AccountController%20%7B%0A%20%20key%0A%20%20multisig%20policy%0A%7D%0Aclass%20AssetDefinition%20%7B%0A%20%20id%3A%20AssetDefinitionId%0A%20%20spec%0A%20%20mintable%0A%20%20metadata%0A%7D%0Aclass%20Asset%20%7B%0A%20%20id%3A%20AssetId%0A%20%20value%0A%7D%0Aclass%20Nft%20%7B%0A%20%20id%3A%20NftId%0A%20%20content%3A%20Metadata%0A%20%20owned_by%3A%20AccountId%0A%7D%0Aclass%20Rwa%20%7B%0A%20%20id%3A%20RwaId%0A%20%20owned_by%3A%20AccountId%0A%20%20quantity%0A%20%20spec%0A%20%20primary_reference%0A%20%20status%0A%20%20metadata%0A%20%20parents%0A%20%20controls%0A%20%20is_frozen%0A%20%20held_quantity%0A%7D%0A%0AWorld%20*--%20Domain%20%3A%20registers%0AWorld%20*--%20Account%20%3A%20registers%0AWorld%20*--%20AssetDefinition%20%3A%20registers%0AWorld%20*--%20Asset%20%3A%20stores%20balances%0AWorld%20*--%20Nft%20%3A%20registers%0AWorld%20*--%20Rwa%20%3A%20registers%20lots%0AAccount%20--%3E%20AccountController%20%3A%20authorized%20by%0ADomain%20--%3E%20Account%20%3A%20owned_by%0AAssetDefinition%20--%3E%20Domain%20%3A%20optional%20projection%0AAsset%20--%3E%20AssetDefinition%20%3A%20definition%0AAsset%20--%3E%20Account%20%3A%20held%20by%0ANft%20--%3E%20Domain%20%3A%20scoped%20by%0ANft%20--%3E%20Account%20%3A%20owned_by%0ARwa%20--%3E%20Account%20%3A%20owned_by"}),e[1]||(e[1]=a('<h2 id="example" tabindex="-1">Example <a class="header-anchor" href="#example" aria-label="Permalink to &quot;Example&quot;">​</a></h2><p>In an Iroha 3 network, <code>wonderland.universal</code> is a domain inside the <code>universal</code> dataspace. <code>alice</code> and <code>rabbit</code> are not encoded as <code>alice@wonderland</code>; they are canonical accounts controlled by their keys or policies. A projected asset definition can still be constructed from a domain and name such as <code>rose</code> in <code>wonderland.universal</code>, while the canonical asset definition address used on the wire is the generated Base58 address.</p>',2)),d(t,{id:"mermaid_0ae3c66a14444033dcb94ab97e8bf5735ac26917757f519cc64aaef6e31f23c7d8fc7f9dcebccdad3a86fd3c7ec9f52cbd0c9ba690ae8720c3cad750700a7c36",text:"classDiagram%0A%0Aclass%20domain_wonderland%20%7B%0A%20%20id%20%3D%20%22wonderland.universal%22%0A%7D%0Aclass%20account_alice%20%7B%0A%20%20id%20%3D%20%22AccountId(controller%3Dalice_key)%22%0A%20%20label%20%3D%20%22alice%22%0A%7D%0Aclass%20account_rabbit%20%7B%0A%20%20id%20%3D%20%22AccountId(controller%3Drabbit_key)%22%0A%20%20label%20%3D%20%22rabbit%22%0A%7D%0Aclass%20asset_rose%20%7B%0A%20%20name%20projection%20%3D%20%22rose%22%0A%20%20domain%20projection%20%3D%20%22wonderland.universal%22%0A%7D%0A%0Adomain_wonderland%20--%3E%20account_alice%20%3A%20owned_by%0Aasset_rose%20--%3E%20domain_wonderland%20%3A%20projected%20under%0Aaccount_alice%20--%3E%20asset_rose%20%3A%20holds%20balance%0Aaccount_rabbit%20--%3E%20asset_rose%20%3A%20may%20receive%20balance"}),e[2]||(e[2]=a('<h2 id="aliases" tabindex="-1">Aliases <a class="header-anchor" href="#aliases" aria-label="Permalink to &quot;Aliases&quot;">​</a></h2><p>Aliases are human-facing names layered over canonical ledger identifiers. They are useful at API, CLI, wallet, and explorer boundaries, but canonical IDs remain the stable identifiers stored in strict ledger fields.</p><table tabindex="0"><thead><tr><th>Target</th><th>Canonical target</th><th>Alias literal</th><th>Backing model</th></tr></thead><tbody><tr><td>User account</td><td>domainless <code>AccountId</code> encoded as an I105 address</td><td><code>name@domain.dataspace</code> or <code>name@dataspace</code></td><td><code>AccountAlias</code>; primary alias is <code>Account.label</code>, extra aliases are bindings</td></tr><tr><td>Asset definition</td><td>canonical <code>AssetDefinitionId</code> Base58 address</td><td><code>name#domain.dataspace</code> or <code>name#dataspace</code></td><td><code>AssetDefinitionAlias</code> bound to an asset definition</td></tr><tr><td>Contract</td><td>canonical Bech32m <code>ContractAddress</code></td><td><code>name::domain.dataspace</code> or <code>name::dataspace</code></td><td><code>ContractAlias</code> bound to a deployed contract address</td></tr><tr><td>Domain name</td><td><code>DomainId</code> in <code>domain.dataspace</code> form</td><td><code>domain.dataspace</code></td><td>SNS <code>domain</code> namespace record</td></tr><tr><td>Dataspace name</td><td>numeric <code>DataSpaceId</code> from the active Nexus catalog</td><td>dataspace alias such as <code>universal</code>, <code>paynet</code>, or <code>zk</code></td><td>SNS <code>dataspace</code> namespace record plus the active dataspace catalog</td></tr></tbody></table><p>Account aliases are the user-facing account names. They survive account rekeying because the alias points at the active account ID through world-state indexes and account rekey records. Use <code>SetPrimaryAccountAlias</code> for the account&#39;s primary label, <code>SetAccountAliasBinding</code> for additional non-primary aliases, and <code>FindAccountByAlias</code> or <code>FindAliasesByAccountId</code> for reads. Account aliases normally require an active SNS account-alias lease acquired with <code>AcquireAccountAliasLease</code> and renewed with <code>RenewAccountAliasLease</code>.</p><p>Asset aliases name asset definitions, not individual account balances. Asset aliases and contract aliases are direct bindings from a readable name to an existing canonical target. Asset aliases are set with <code>SetAssetDefinitionAlias</code>; the alias name segment must match the asset definition display name or projected definition name. Contract aliases are set with <code>SetContractAlias</code>; the alias dataspace must match the dataspace encoded in the contract address. Both bindings can carry <code>lease_expiry_ms</code>; after expiry they stop resolving when the grace window elapses and are swept from world-state indexes.</p><p>Domains do not have a separate <code>DomainAlias</code> object. A domain identifier is already a dataspace-qualified name such as <code>payments.universal</code>. SNS tracks lease ownership for domain names in the <code>domain</code> namespace and for dataspace aliases in the <code>dataspace</code> namespace. The reserved <code>universal</code> dataspace alias must remain defined.</p><h2 id="related-docs" tabindex="-1">Related docs <a class="header-anchor" href="#related-docs" aria-label="Permalink to &quot;Related docs&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Topic</th><th>Where to go</th></tr></thead><tbody><tr><td>Domains</td><td><a href="/iroha-2-docs/blockchain/domains.html">Domains</a></td></tr><tr><td>Accounts</td><td><a href="/iroha-2-docs/blockchain/accounts.html">Accounts</a></td></tr><tr><td>Assets</td><td><a href="/iroha-2-docs/blockchain/assets.html">Assets</a></td></tr><tr><td>NFTs</td><td><a href="/iroha-2-docs/blockchain/nfts.html">NFTs</a></td></tr><tr><td>Real-world assets</td><td><a href="/iroha-2-docs/blockchain/rwas.html">Real-World Assets</a></td></tr><tr><td>Metadata</td><td><a href="/iroha-2-docs/blockchain/metadata.html">Metadata</a></td></tr><tr><td>Registration and transfer instructions</td><td><a href="/iroha-2-docs/blockchain/instructions.html">Instructions</a></td></tr><tr><td>Runtime permissions</td><td><a href="/iroha-2-docs/blockchain/permissions.html">Permissions</a></td></tr><tr><td>Naming rules</td><td><a href="/iroha-2-docs/reference/naming.html">Naming rules</a></td></tr></tbody></table>',8))])}const b=o(i,[["render",r]]);export{p as __pageData,b as default};
